import requests
from bs4 import BeautifulSoup
import re
import time
import json

headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'}

with open('/workspace/weekly_reports_2025.txt', 'r', encoding='utf-8') as f:
    reports = [line.strip().split('\t') for line in f if line.strip()]

all_events = []
completion_kws = ['竣工', '完工', '投运', '投产', '交付使用', '开通', '启用', '移交生产', '落成', '移交', '正式运营', '投产运营', '正式投产']

for title, url in reports:
    try:
        year_match = re.search(r'(\d{4})\.', title)
        report_year = int(year_match.group(1)) if year_match else 2025

        r = requests.get(url, headers=headers, timeout=15)
        if r.status_code == 200:
            soup = BeautifulSoup(r.text, 'lxml')
            text = soup.get_text(separator='\n', strip=True)
            lines = text.split('\n')

            for i, line in enumerate(lines):
                if any(kw in line for kw in completion_kws) and 10 < len(line) < 100:
                    # Get next 2 non-empty lines as detail
                    details = []
                    for j in range(i+1, min(len(lines), i+5)):
                        if len(lines[j]) > 20:
                            details.append(lines[j])
                            if len(details) >= 2:
                                break

                    detail_text = ' '.join(details)

                    if detail_text and re.search(r'\d+月\d+日', detail_text):
                        all_events.append({
                            'report': title,
                            'year': report_year,
                            'title_line': line,
                            'detail': detail_text[:600]
                        })

        time.sleep(0.3)
    except Exception as e:
        pass

print(f'Total events: {len(all_events)}')

with open('/workspace/all_events_v2.json', 'w', encoding='utf-8') as f:
    json.dump(all_events, f, ensure_ascii=False, indent=2)

for i, e in enumerate(all_events, 1):
    print(f'{i}. [{e["report"]}] {e["title_line"]}')
